VALUES
  ('real-estate-moex-02132', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲為定作人，與乙訂立承攬契約，由乙為甲建一房屋。關於此案例，下列敘述何者正確？', '["乙得就承攬之報酬額，對於將來完成之甲之房屋，請求預為抵押權之登記", "工作未完成前，定作人甲不得隨時終止契約", "定作人甲所供給之材料，因不可抗力而毀損者，承攬人須負其責", "如乙所蓋房屋有瑕疵，甲於房屋交付後二年始發見者，不得請求乙修補"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02133', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列敘述，何者正確？', '["契約之要約人，因要約而受拘束，不可預先聲明不受拘束", "貨物標定賣價陳列者，視為要約之引誘", "對話為要約者，非立時承諾，即失其拘束力，因此不得定承諾期限", "將要約變更而承諾者，視為拒絕原要約而為新要約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02134', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '乙承租甲所有之土地種植果樹，約定租期二年，未訂立字據。關於此案例，下列敘述何者正確？', '["此為定期租賃契約", "乙於契約成立後，得請求甲為地上權之登記", "若甲於土地交給乙占有後，將土地所有權移轉給丙，乙仍可主張租賃契約對丙成立", "就租賃物應納之一切稅捐，由出租人甲負擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02135', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列關於不當得利之敘述，何者正確？', '["無法律上之原因而受利益，致他人受損害者，應返還其利益", "因清償債務而為給付，於給付時明知無給付之義務者，得請求返還", "不當得利之受領人，只須返還其所受之利益，如本於該利益更有所取得者，無須返還", "不當得利之受領人，不知無法律上之原因，縱其所受之利益已不存在者，仍應負返還之責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02136', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何者為附解除條件之法律行為？', '["甲如能考100分，乙就給甲100元", "甲向乙借1萬元，約定乙每月支付利息100元", "當甲大學畢業時，乙的房屋就不再出租給甲", "甲乙間約定於民國105年時，二人即結婚"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02137', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於死亡宣告，下列敘述何者錯誤？', '["得聲請死亡宣告者，僅限於失蹤人之利害關係人", "死亡宣告係私法上的制度，不生公法上的效果", "死亡宣告在於結束失蹤人原住居所為中心之法律關係，而不在剝奪失蹤人之權利能力", "死亡宣告為推定死亡，故允許提出反證而撤銷死亡宣告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02138', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於財團法人之敘述，下列何者正確？', '["其權利能力始於訂立捐助章程，終於清算解散", "財團為公益法人，其設立須經地方法院許可", "董事有數人者，除章程另有規定外，各董事均得代表法人", "財團法人並非自然人，無侵權行為能力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02139', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於法人依其性質，不得享有下列何種權利？', '["姓名權", "自由權", "專利權", "名譽權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02140', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲到乙所開設之賭場賭博，賭輸了10萬元，下列敘述何者正確？', '["賭博為甲乙間債務發生之原因關係，所以甲應支付乙10萬", "如甲已經付款給乙，則甲得主張賭博行為違反公序良俗無效，依不當得利向乙請求返還", "如甲已經付款給乙，雖甲得主張賭博行為違反公序良俗無效，但甲之給付為出於不法原因之給付，所 以不得向乙請求返還", "如甲已經付款給乙，甲得主張侵權行為，向乙請求損害賠償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02141', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲僱傭17歲未婚之乙為店員，並授與代理權以甲之名義販售物品，若甲之法定代理人均不同意。則：', '["僱傭契約無效，代理權授與有效", "僱傭契約無效，代理權授與亦無效", "僱傭契約有效，代理權授與無效", "僱傭契約有效，代理權授與亦有效"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 19, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
